/** @since 5.0 */
export type HistogramState = "disabled" | "ready";

/**
 * Function used to style or attach custom interaction to histogram bars. This function should be set to the
 * [Histogram.barCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/Histogram/#barCreatedFunction) property. It fires
 * for each bar when it is created.
 *
 * @param index - The index of the histogram bar. This directly corresponds
 *   to the index of the associated [bin](https://developers.arcgis.com/javascript/latest/references/core/widgets/Histogram/#bins).
 * @param element - The histogram bar element to style.
 * @since 5.0
 */
export type BarCreatedFunction = (index: number, element: SVGElement) => void;

/**
 * Function used to style [Histogram.dataLines](https://developers.arcgis.com/javascript/latest/references/core/widgets/Histogram/#dataLines). This function should be set to the
 * [Histogram.dataLineCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/Histogram/#dataLineCreatedFunction) property. It fires
 * when each data line is created.
 *
 * @param lineElement - The SVG element representing the data line rendered
 *   on the histogram.
 * @param labelElement - The SVG element representing the label
 *    rendered on the histogram for the associated line element.
 * @param index - The index of the data line.
 * @since 5.0
 */
export type DataLineCreatedFunction = (lineElement: SVGElement, labelElement?: SVGElement | null | undefined, index?: number | null | undefined) => void;

/** @since 5.0 */
export interface DataLineInfos {
  /**
   * The value on the data axis of the histogram where a line will be rendered.
   *
   * @since 5.0
   */
  value: number;
  /**
   * The label associated with the line.
   *
   * @since 5.0
   */
  label?: string | number | null;
}